import{_ as a,o as r,c as n,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"香港网银出金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"withdrawal/hk-online-banking.md","filePath":"zh-CN/withdrawal/hk-online-banking.md"}'),e={name:"withdrawal/hk-online-banking.md"};function i(s,t,d,l,h,p){return r(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="香港网银出金" tabindex="-1">香港网银出金 <a class="header-anchor" href="#香港网银出金" aria-label="Permalink to &quot;香港网银出金&quot;">​</a></h1><p>长桥香港账户出金至香港银行卡支持三种方式：FPS 转数快、网银转账、银证转账（仅民生银行）。系统根据银行卡类型自动匹配。</p><p>操作步骤见 <a href="./如何出金到香港银行卡">如何出金到香港银行卡</a>。</p><h2 id="fps-转数快出金" tabindex="-1">FPS 转数快出金 <a class="header-anchor" href="#fps-转数快出金" aria-label="Permalink to &quot;FPS 转数快出金&quot;">​</a></h2><p><strong>支持币种</strong>：港元（HKD）</p><p><strong>到账时间</strong></p><table tabindex="0"><thead><tr><th>提交时间</th><th>预计到账时间</th></tr></thead><tbody><tr><td>交易日 09:00 - 15:30</td><td>最快 2 小时内</td></tr><tr><td>其他时段</td><td>下一个交易日 10:00 前</td></tr></tbody></table><p><strong>手续费</strong>：免费</p><p><strong>单笔限额</strong>：最高 100 万港元</p><p><strong>大额出金</strong>：超过 50 万 HKD 需人工审批，交易日 15:30 前提交预计当天完成，15:30 后提交预计 T+1 完成。</p><h2 id="网银转账出金" tabindex="-1">网银转账出金 <a class="header-anchor" href="#网银转账出金" aria-label="Permalink to &quot;网银转账出金&quot;">​</a></h2><p><strong>支持币种</strong>：港元（HKD）、美元（USD）</p><p><strong>到账时间</strong>：交易日 15:30 前提交预计当天出金，15:30 后提交预计下一个交易日出金</p><p><strong>手续费</strong>：出金港币免费；出金美元长桥不收费，银行可能收费，以实际到账为准</p><p><strong>大额出金</strong>：超过 50 万 HKD / 10 万 USD 需人工审批</p><h2 id="银证转账出金-民生银行" tabindex="-1">银证转账出金（民生银行） <a class="header-anchor" href="#银证转账出金-民生银行" aria-label="Permalink to &quot;银证转账出金（民生银行）&quot;">​</a></h2><p><strong>支持银行</strong>：仅支持民生香港银行卡且银证授权成功</p><p><strong>支持币种</strong>：港元（HKD）、美元（USD）</p><p><strong>到账时间</strong></p><table tabindex="0"><thead><tr><th>提交时间</th><th>预计到账时间</th></tr></thead><tbody><tr><td>交易日 09:00 - 15:30</td><td>最快 2 小时内</td></tr><tr><td>其他时段</td><td>下一个交易日 10:00 前</td></tr></tbody></table><p><strong>手续费</strong>：免费</p><p><strong>大额出金</strong>：超过 50 万 HKD / 10 万 USD 需人工审批</p><h2 id="同名账户、结算周期与反洗钱限制" tabindex="-1">同名账户、结算周期与反洗钱限制 <a class="header-anchor" href="#同名账户、结算周期与反洗钱限制" aria-label="Permalink to &quot;同名账户、结算周期与反洗钱限制&quot;">​</a></h2><ul><li>提取资金银行账户名必须与长桥证券账户名同名，不可使用他人账户，资金不能提取到第三方支付平台或联名账户</li><li>提交材料认证但未入金时不允许出金</li><li>港股交易 T+2 结算，美股交易 T+1 结算，需等结算完成后才可出金</li><li>账户部分币种存在欠款时，会影响其他币种的可提金额</li><li>节假日及休市期间银行不处理资金业务，可能影响到账时间</li><li>建议选择香港银行卡港元出金，系统会优先匹配 FPS</li><li>长桥依据反洗钱法规对部分出金申请进行审查，可能设定短暂提款限制期</li></ul>',24)])])}const c=a(e,[["render",i]]);export{b as __pageData,c as default};
